from enum import Enum

class UserRole(Enum):
    ADMIN = "admin"
    USER = "user"

# Consolidating Submitter and Talent roles into a generic User role
class User:
    def __init__(self, role: UserRole):
        self.role = role

# Example of how to use the User class
def create_user(role: str):
    if role in UserRole.__members__:
        return User(UserRole[role])
    else:
        raise ValueError("Invalid role")

# Unit tests for critical behaviors
def test_create_user():
    user = create_user("USER")
    assert user.role == UserRole.USER

    admin = create_user("ADMIN")
    assert admin.role == UserRole.ADMIN

    try:
        create_user("SUBMITTER")
    except ValueError as e:
        assert str(e) == "Invalid role"

    try:
        create_user("TALENT")
    except ValueError as e:
        assert str(e) == "Invalid role"

# Adversarial/edge-case tests
def test_invalid_role():
    try:
        create_user("INVALID_ROLE")
    except ValueError as e:
        assert str(e) == "Invalid role"

# Running tests
if __name__ == "__main__":
    test_create_user()
    test_invalid_role()
    print("All tests passed.")
